    data = json.load(open(f))
    for k, v in data.items():
        if v and v.get("_bibtex"):
            all_bibtex[int(k)] = v["_bibtex"].strip()
            all_info[int(k)] = v.get("title", "")
        elif v:
            all_info[int(k)] = v

# Also load original results
for f in ["/tmp/isolated_workspace_1091/dblp_results.json"]:
    if os.path.exists(f):
        data = json.load(open(f))
        for k, v in data.items():
            ki = int(k)
            if v and v.get("_bibtex") and ki not in all_bibtex:
                all_bibtex[ki] = v["_bibtex"].strip()
                all_info[ki] = v.get("title", "")

print("Papers with BibTeX entries:")
